import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"中国古动物馆","description":"","frontmatter":{},"headers":[],"relativePath":"museums/paleo-zoo.md","filePath":"museums/paleo-zoo.md","lastUpdated":1784712887000}'),n={name:"museums/paleo-zoo.md"};function o(d,t,s,i,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="中国古动物馆" tabindex="-1">中国古动物馆 <a class="header-anchor" href="#中国古动物馆" aria-label="Permalink to &quot;中国古动物馆&quot;">​</a></h1><blockquote><p>&quot;亚洲最大的古动物博物馆，恐龙迷的天堂。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>中国古动物馆位于北京市西城区，是中国第一座以古生物化石为载体的国家级自然科学类专题博物馆，也是亚洲最大的古动物博物馆。博物馆隶属于中国科学院古脊椎动物与古人类研究所，收藏了大量珍贵的古生物化石。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-16:30（周一闭馆）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">20元（学生10元）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线动物园站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区西直门外大街142号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="创建" tabindex="-1">创建 <a class="header-anchor" href="#创建" aria-label="Permalink to &quot;创建&quot;">​</a></h3><p>中国古动物馆创建于1994年，依托中国科学院古脊椎动物与古人类研究所丰富的馆藏建立。</p><h3 id="发展" tabindex="-1">发展 <a class="header-anchor" href="#发展" aria-label="Permalink to &quot;发展&quot;">​</a></h3><p>1995年，古动物馆正式对外开放。此后，博物馆不断扩大规模，增加展览内容。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="外观" tabindex="-1">外观 <a class="header-anchor" href="#外观" aria-label="Permalink to &quot;外观&quot;">​</a></h3><p>中国古动物馆建筑外形似一个巨大的恐龙蛋，寓意生命的起源。</p><h3 id="内部" tabindex="-1">内部 <a class="header-anchor" href="#内部" aria-label="Permalink to &quot;内部&quot;">​</a></h3><p>博物馆内部有多个展厅，布局合理，参观路线清晰。</p><h2 id="常设展览" tabindex="-1">常设展览 <a class="header-anchor" href="#常设展览" aria-label="Permalink to &quot;常设展览&quot;">​</a></h2><h3 id="古脊椎动物展厅" tabindex="-1">古脊椎动物展厅 <a class="header-anchor" href="#古脊椎动物展厅" aria-label="Permalink to &quot;古脊椎动物展厅&quot;">​</a></h3><p>这是古动物馆的核心展厅，展示了从鱼到人演化过程中的各种古脊椎动物。</p><h4 id="展览内容" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容" aria-label="Permalink to &quot;展览内容&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">展区</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>古鱼类</strong></td><td style="text-align:left;">各种古代鱼类化石</td></tr><tr><td style="text-align:left;"><strong>古两栖类</strong></td><td style="text-align:left;">古代两栖动物化石</td></tr><tr><td style="text-align:left;"><strong>古爬行类</strong></td><td style="text-align:left;">恐龙、翼龙等化石</td></tr><tr><td style="text-align:left;"><strong>古鸟类</strong></td><td style="text-align:left;">古代鸟类化石</td></tr><tr><td style="text-align:left;"><strong>古哺乳类</strong></td><td style="text-align:left;">古代哺乳动物化石</td></tr><tr><td style="text-align:left;"><strong>古人类</strong></td><td style="text-align:left;">古人类化石</td></tr></tbody></table><h3 id="恐龙展厅" tabindex="-1">恐龙展厅 <a class="header-anchor" href="#恐龙展厅" aria-label="Permalink to &quot;恐龙展厅&quot;">​</a></h3><p>恐龙展厅是古动物馆最受欢迎的展厅。</p><h4 id="恐龙化石" tabindex="-1">恐龙化石 <a class="header-anchor" href="#恐龙化石" aria-label="Permalink to &quot;恐龙化石&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">恐龙</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>许氏禄丰龙</strong></td><td style="text-align:left;">中国第一具装架的恐龙化石</td></tr><tr><td style="text-align:left;"><strong>马门溪龙</strong></td><td style="text-align:left;">中国最大的恐龙之一</td></tr><tr><td style="text-align:left;"><strong>沱江龙</strong></td><td style="text-align:left;">剑龙类恐龙</td></tr><tr><td style="text-align:left;"><strong>霸王龙</strong></td><td style="text-align:left;">肉食性恐龙</td></tr><tr><td style="text-align:left;"><strong>三角龙</strong></td><td style="text-align:left;">草食性恐龙</td></tr><tr><td style="text-align:left;"><strong>鸭嘴龙</strong></td><td style="text-align:left;">草食性恐龙</td></tr></tbody></table><h4 id="恐龙装架" tabindex="-1">恐龙装架 <a class="header-anchor" href="#恐龙装架" aria-label="Permalink to &quot;恐龙装架&quot;">​</a></h4><p>展厅内有多个恐龙装架，包括：</p><ul><li><strong>马门溪龙装架</strong>：长26米，高8米</li><li><strong>霸王龙装架</strong>：威猛霸气</li><li><strong>三角龙装架</strong>：三只角非常醒目</li></ul><h3 id="古人类展厅" tabindex="-1">古人类展厅 <a class="header-anchor" href="#古人类展厅" aria-label="Permalink to &quot;古人类展厅&quot;">​</a></h3><p>古人类展厅展示了人类演化的历程。</p><h4 id="展览内容-1" tabindex="-1">展览内容 <a class="header-anchor" href="#展览内容-1" aria-label="Permalink to &quot;展览内容&quot;">​</a></h4><ul><li><strong>古猿</strong>：人类的祖先</li><li><strong>直立人</strong>：北京猿人、元谋人、蓝田人等</li><li><strong>早期智人</strong>：尼安德特人等</li><li><strong>晚期智人</strong>：现代人的直接祖先</li></ul><h4 id="北京猿人" tabindex="-1">北京猿人 <a class="header-anchor" href="#北京猿人" aria-label="Permalink to &quot;北京猿人&quot;">​</a></h4><p>展厅内有北京猿人的头盖骨模型（原件在抗战中失踪）。</p><h3 id="特展厅" tabindex="-1">特展厅 <a class="header-anchor" href="#特展厅" aria-label="Permalink to &quot;特展厅&quot;">​</a></h3><p>特展厅定期举办各种特展，包括：</p><ul><li>新发现的化石展览</li><li>国际交流展览</li><li>科普教育展览</li></ul><h2 id="珍贵化石" tabindex="-1">珍贵化石 <a class="header-anchor" href="#珍贵化石" aria-label="Permalink to &quot;珍贵化石&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">化石</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>许氏禄丰龙</strong></td><td style="text-align:left;">中国第一具装架的恐龙化石</td></tr><tr><td style="text-align:left;"><strong>马门溪龙</strong></td><td style="text-align:left;">中国最大的恐龙化石之一</td></tr><tr><td style="text-align:left;"><strong>北京猿人头盖骨</strong></td><td style="text-align:left;">复制品，原件失踪</td></tr><tr><td style="text-align:left;"><strong>黄河象</strong></td><td style="text-align:left;">中国最大的古象化石</td></tr><tr><td style="text-align:left;"><strong>披毛犀</strong></td><td style="text-align:left;">冰河时期的犀牛</td></tr><tr><td style="text-align:left;"><strong>猛犸象</strong></td><td style="text-align:left;">史前巨兽</td></tr></tbody></table><h2 id="科研价值" tabindex="-1">科研价值 <a class="header-anchor" href="#科研价值" aria-label="Permalink to &quot;科研价值&quot;">​</a></h2><p>中国古动物馆依托中国科学院古脊椎动物与古人类研究所，具有极高的科研价值。</p><h3 id="科研成果" tabindex="-1">科研成果 <a class="header-anchor" href="#科研成果" aria-label="Permalink to &quot;科研成果&quot;">​</a></h3><ul><li><strong>古鱼类研究</strong>：世界领先</li><li><strong>恐龙研究</strong>：成果丰硕</li><li><strong>古人类研究</strong>：北京猿人等</li><li><strong>古哺乳动物研究</strong>：成果丰硕</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约2-3小时）</strong>：</p><p>古脊椎动物展厅 → 恐龙展厅 → 古人类展厅 → 特展厅</p><p><strong>恐龙迷路线</strong>：</p><p>恐龙展厅（重点） → 古脊椎动物展厅 → 古人类展厅</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">4号线动物园站D口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">7路、15路、19路等动物园站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从北京北站步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>恐龙必看</strong>：恐龙展厅是精华</li><li><strong>科研价值高</strong>：了解最新科研成果</li><li><strong>亲子游</strong>：非常适合带孩子参观</li><li><strong>避开高峰</strong>：周末人较多，建议工作日</li><li><strong>结合游览</strong>：可与北京天文馆、动物园一起游览</li><li><strong>讲解服务</strong>：可租借语音导览</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">北京天文馆</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">天文科普</td></tr><tr><td style="text-align:left;">北京动物园</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">大熊猫</td></tr><tr><td style="text-align:left;">北京展览馆</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">展览中心</td></tr><tr><td style="text-align:left;">西直门商圈</td><td style="text-align:center;">地铁1站</td><td style="text-align:left;">商业区</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市西城区西直门外大街142号 <strong>📞 电话</strong>：010-88369280 <strong>🌐 官网</strong>：<a href="http://www.paleozoo.cn" target="_blank" rel="noreferrer">www.paleozoo.cn</a></p>',57)])])}const y=e(n,[["render",o]]);export{f as __pageData,y as default};
